code.C:
#include <stdio.h>
int main() {
    int T = 1; // single test case as there is no input
    for (int tc = 0; tc < T; ++tc) {
        for (int i = 1; i <= 5; ++i) {
            printf("%d - %d", i, i * i);
            if (i < 5) printf("\n");
        }
        if (tc < T - 1) printf("\n");
    }
    return 0;
}

